def most_frequent_char(text):
    counts = {}
    for ch in text:
        if ch != ' ':
            counts[ch] = counts.get(ch, 0) + 1
    if not counts:
        return ""
    max_count = max(counts.values())
    for ch in text:
        if ch != ' ' and counts[ch] == max_count:
            return ch

unit_tests:
import unittest

class TestSolution(unittest.TestCase):
    def test_basic(self):
        self.assertEqual(most_frequent_char("hello world"), 'l')

    def test_banana(self):
        self.assertEqual(most_frequent_char("banana"), 'a')

    def test_tie_returns_first(self):
        self.assertEqual(most_frequent_char("aabbcc"), 'a')

    def test_hidden_empty_string(self):
        self.assertEqual(most_frequent_char(""), "")

    def test_hidden_only_spaces(self):
        self.assertEqual(most_frequent_char("   "), "")

    def test_hidden_single_char(self):
        self.assertEqual(most_frequent_char("x"), 'x')

    def test_hidden_case_sensitive(self):
        self.assertEqual(most_frequent_char("AaAa"), 'A')

    def test_hidden_mississippi(self):
        self.assertEqual(most_frequent_char("Mississippi"), 'i')

    def test_hidden_spaces_between(self):
        self.assertEqual(most_frequent_char("a b a b a"), 'a')

    def test_hidden_special_chars(self):
        self.assertEqual(most_frequent_char("!!@@!!"), '!')

if __name__ == '__main__':
    unittest.main()
